 7→import { CORRELATION_ID_HEADER_NAME } from '@constants/req.constants';
 8→
 9→@Injectable()
10→export class CorrelationIdMiddleware implements NestMiddleware {
11→	use(req: FastifyRequest['raw'], _: FastifyReply['raw'], next: () => void): void {
12→		const correlationIdFromHeader = req.headers[CORRELATION_ID_HEADER_NAME] as string;
13→
14→		const id = correlationIdFromHeader || randomUUID();
15→
16→		correlator.withId({
17→			correlationId: id,
18→			fn: () => {
19→				next();
20→			},
21→		});
22→	}
23→}
