28→export function CronJobExecution(options: CronJobExecutionOptions): MethodDecorator {
29→	const { jobName, context = {} } = options;
30→
31→	return function (
32→		target: unknown,
33→		_propertyKey: string | symbol,
34→		descriptor: PropertyDescriptor,
35→	) {
36→		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
37→		const className = (target as { constructor: { name: string } }).constructor.name;
38→		const logger = new Logger(className);
39→
40→		descriptor.value = async function (...args: unknown[]) {
41→			const startTime = performance.now();
42→
43→			logger.log(`Starting ${jobName}`);
44→			bufferedRollbar.info({
45→				msg: `Starting ${jobName}`,
46→				context: { command: jobName, ...context },
47→			});
48→
49→			try {
50→				await originalMethod.apply(this, args);
51→
52→				const executionTimeMs = performance.now() - startTime;
53→
54→				logger.log(`${jobName} completed. Duration: ${formatDuration(executionTimeMs)}`);
55→				bufferedRollbar.info({
56→					msg: `${jobName} completed`,
57→					context: {
58→						command: jobName,
59→						executionTimeMs,
60→						executionTimeFormatted: formatDuration(executionTimeMs),
61→						...context,
62→					},
63→				});
64→
65→				void bufferedRollbar.wait().then(() => {
66→					process.exit(0);
67→				});
68→			} catch (error) {
69→				const executionTimeMs = performance.now() - startTime;
70→
71→				logger.error(
72→					`${jobName} failed after ${formatDuration(executionTimeMs)}:`,
73→					(error as Error).stack,
74→				);
75→				bufferedRollbar.error({
76→					err: `${jobName} failed`,
77→					context: {
78→						command: jobName,
79→						executionTimeMs,
80→						executionTimeFormatted: formatDuration(executionTimeMs),
81→						error: error instanceof Error ? error.message : String(error),
82→						...context,
83→					},
84→				});
85→
86→				void bufferedRollbar.wait().then(() => {
87→					process.exit(1);
88→				});
89→			}
90→		};
